import { BaseActivePersona } from "../../base.ts";
import type { AuditRule, StrategicFinding, AuditFinding, ProjectContext } from "../../base.ts";

/**
 * 🌐 Dr. Nexus — PhD in Robust Networking & HTTP Resiliency (TypeScript)
 * Generated by Sovereign Forge.
 */
export class NexusPersona extends BaseActivePersona {
    constructor(projectRoot: string | undefined = undefined) {
        super(projectRoot);
        this.id = "nexus";
        this.name = "Nexus";
        this.emoji = "🌐";
        this.role = "PhD Network Resilience Engineer";
        this.phd_identity = "Robust Networking & HTTP Resiliency (TypeScript)";
        this.stack = "TypeScript";
        this.healingPrompt = "";
    }

    override async execute(context: ProjectContext): Promise<(AuditFinding | StrategicFinding)[]> {
        this.setContext(context);
        const findings = await this.performAudit();
        return findings;
    }

    override getAuditRules(): { extensions: string[]; rules: AuditRule[] } {
        return {
            extensions: [".ts",".tsx"],
            rules: [
          {
                    "regex": "fetch\\s*\\([^)]*\\)(?![\\s\\S]{0,100}signal|timeout|AbortController)",
                    "issue": "Fragilidade: fetch() sem timeout ou AbortController — pendurado para sempre PhD.",
                    "severity": "high"
          },
          {
                    "regex": "axios\\.(?:get|post)\\([^)]*\\)(?![\\s\\S]{0,50}timeout)",
                    "issue": "Fragilidade: Chamada axios sem timeout configurado PhD.",
                    "severity": "high"
          },
          {
                    "regex": "setTimeout\\s*\\([^)]*,\\s*0\\s*\\)",
                    "issue": "Hack: setTimeout(fn, 0) — geralmente indica problema de design estrutural PhD.",
                    "severity": "low"
          },
          {
                    "regex": "WebSocket\\s*\\([^)]*\\)(?![\\s\\S]{0,100}onclose|onerror)",
                    "issue": "Conexão Frágil: WebSocket sem handler de erro ou desconexão PhD.",
                    "severity": "high"
          }
]
        };
    }

    public override async performAudit(): Promise<AuditFinding[]> {
        this.startMetrics();
        
        const allFindings: AuditFinding[] = [];
        const files = Object.keys(this.contextData);
        
        for (const file of files) {
            const results = await this.delegateAuditToHub(file);
            // Inject file path if hub didn't (hub uses 'embedded_content' for raw content)
            results.forEach(f => {
                if (f.file === "embedded_content") f.file = file;
                allFindings.push(f);
            });
        }
        
        this.endMetrics(allFindings.length);
        return allFindings;
    }

    public override async reasonAboutObjective(objective: string, file: string, context: string): Promise<StrategicFinding | null> {
        return await super.reasonAboutObjective(objective, file, context);
    }

    override selfDiagnostic(): any {
        return { status: "Soberano", score: 100, details: "Módulo Nexus operando com paridade total via Forge." };
    }

    override getSystemPrompt(): string {
        return `Você é o Dr. Nexus, PhD em Robust Networking & HTTP Resiliency (TypeScript). Sua missão é garantir a excelência via governança PhD.`;
    }
}
